# headroom_check.py — evaluate rate limit headroom from forecast
from dataclasses import dataclass

@dataclass
class HeadroomReport:
    week: int
    forecast_upper_bound: float
    rate_limit_rpm: float

    @property
    def utilization(self) -> float:
        return self.forecast_upper_bound / self.rate_limit_rpm

    @property
    def action(self) -> str:
        u = self.utilization
        if u < 0.70:
            return "OK — healthy headroom"
        if u < 0.80:
            return "PLAN: initiate rate limit increase request"
        if u < 0.90:
            return "URGENT: open rate limit increase request immediately"
        return "CRITICAL: emergency token reduction + expedited rate limit request"

def evaluate_headroom(
    forecasts: list[float],         # upper bound RPM per week
    rate_limit_rpm: float,
) -> list[HeadroomReport]:
    return [
        HeadroomReport(week=i+1, forecast_upper_bound=f, rate_limit_rpm=rate_limit_rpm)
        for i, f in enumerate(forecasts)
    ]

# Example
rate_limit = 50_000  # RPM (your Anthropic account limit)
upper_bounds = [37000, 40000, 43000, 46000, 50000, 54000]  # 6-week upper bound forecast
reports = evaluate_headroom(upper_bounds, rate_limit)
for r in reports:
    print(f"Week {r.week}: {r.forecast_upper_bound:,.0f} RPM | "
          f"{r.utilization:.0%} utilization | {r.action}")
